var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CITIZEN_EXTRA_NULL_NULL","text":{"KOREA":"저, 저기 봐! 뭐가 나타났어!","JPN":"あ、あれを見ろ！　何かが現れた！","ENG":"L-look! Something else suddenly appeared in the sky!","TWN":"快…快看！那邊又出現了什麼東西！"},"stage":{"bg":"GRONIA_STREET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CITIZEN_EXTRA_NULL_NULL","text":{"KOREA":"비행기는 아닌 것 같은데…? 사람인가?","JPN":"飛行機じゃなさそうだけど……？　人間、なのか？","ENG":"I don't think it's an airplane... Is it a person?","TWN":"那好像不是飛機……？難道是人？"},"stage":{"bg":"GRONIA_STREET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"이봐, 망원경! 망원경으로 봐 봐!","JPN":"おい、望遠鏡！　望遠鏡で見てみろ！","ENG":"Hey, the scope! Look through the scope!","TWN":"喂、快用望眼鏡看看！"},"stage":{"bg":"GRONIA_STREET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"브레히트 중사다……! 저, 정말 왔어!","JPN":"ブレヒト軍曹だ……！　ほ、本当に来てくれたんだ！","ENG":"It's Sergeant Brecht...! S-she really came!","TWN":"是布萊希特中士……！她真的來了！"},"stage":{"bg":"GRONIA_STREET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그리 가깝지만은 않은 거리였을 텐데, 꽤 이른 시각에 당도했네요. 브레히트 중사.","JPN":"近くはない距離だったはずですが、案外早く着きましたね。ブレヒト軍曹。","ENG":"It may not have been that close, Sergeant Brecht. But you arrived quite early.","TWN":"這麼遠的距離，追得還蠻快的，布萊希特中士。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"공간 도약의 조짐도 없이…. 순수하게 속도만으로 오셨군요.","JPN":"空間跳躍の兆しもなく……純粋にスピードだけで来たのですか。","ENG":"I didn't sense a space jump... so it must've been pure speed.","TWN":"甚至沒有使用空間跳躍…單純是速度取勝。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"네퀴티아….","JPN":"ネキティア……","ENG":"Nequitia...","TWN":"莉奎蒂亞……"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"아니, 레버넌트 씨.","JPN":"いいえ、レヴナントさん。","ENG":"No, Revenant.","TWN":"喂，亡靈。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"……그 이름으로 부르지 말아 주시죠. 불쾌합니다.","JPN":"……その名前で呼ばないでほしいですね。不快です。","ENG":"...Please do not call me that. It displeases me.","TWN":"……請你不要用那個名字稱呼我，聽起來很不舒服。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"그럼 어째서 타나베린으로 온 거죠?","JPN":"じゃあ、どうしてタナベリンに来たんですか？","ENG":"Then why did you come to Tanaberin?","TWN":"那你為什麼要來到達那貝林？"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"그것도 아주머니를 죽이자마자, 무언가 떠오르기라도 한 듯이.","JPN":"それもおばさんを殺してすぐ、何かを思い出したかのように。","ENG":"It's as if you realized something right after killing Madam Schneider.","TWN":"是不是在你殺害伯母後，突然想起什麼。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"실례지만, 브레히트 중사. 타인을 예단하는 것은 매우 위험한 행동입니다.","JPN":"失礼ですが、ブレヒト軍曹。他人の事を決めつけることはとても危険な行為ですよ。","ENG":"Pardon me, Sergeant Brecht. But presuming the actions of others is dangerous.","TWN":"抱歉，布萊希特中士。像你這樣擅自揣摩別人心思的行為是很危險的。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"제가 당신을 높이 평가하는 것을 다행으로 여기세요.","JPN":"私があなたを高く評価していることを幸運と思いなさい。","ENG":"You should be grateful that I think highly of you.","TWN":"你要慶倖我對你保有著頗高的評價。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"궁금하다면 말씀해 드리지요.","JPN":"気になるのでしたら、話してさしあげましょう。","ENG":"If you must know, then I shall indulge.","TWN":"既然你很好奇，我就告訴你。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"아시다시피, 멘탈 프린팅를 보완해 나가기 위해서는 많은 실험체를 공급할 수 있어야 합니다.","JPN":"ご存じのとおり、メンタル・プリンティングを補完していくためには、多くの実験体を供給できなければなりません。","ENG":"As you may be aware, I require a large number of test subjects in order to further Mental Printing.","TWN":"如你所知，要完整進行智力複印，就必須取得足夠數量的實驗體。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그리고 이 나라는…. 연구에 활용하기에 적합한 곳입니다.","JPN":"そしてこの国は……研究にうってつけの場所。","ENG":"And this nation... is most appropriate for my research.","TWN":"而這個國家……非常適合我進行研究。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"카르멘의 망상 속에 존재하던 가축 사육장과 가장 근접한 지역이죠.","JPN":"カルメンの妄想の中に存在していた家畜飼育場にもっとも類似している地域なのです。","ENG":"It is the area that most closely resembles the kennel from Carmen's delusions.","TWN":"這個地區與卡門曾經妄想的寵物飼養場非常類似。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그것뿐이에요. 다른 이유는 없습니다.","JPN":"それだけです。他に理由はありません。","ENG":"That is all. There is no other reason.","TWN":"僅此而已，沒有別的理由。"},"stage":{"bg":"SKY_SUNSET","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"……그래요, 레버넌트 씨.","JPN":"……そうですか、レヴナントさん。","ENG":"...Okay, Revenant.","TWN":"……好吧，亡靈。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"무성의하게 꾸민 거짓말도 모르는 척 넘어가 주긴 이제 지쳤어요.","JPN":"適当に作った嘘に付き合ってあげたいんですが、もう疲れたんですよ。","ENG":"I'm tired of pretending that I don't know about your ludicrous lies.","TWN":"我不想再假裝沒發現你胡亂編造的謊言。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"짧게 알고 지냈지만, 당신이 솔직하지 못한 사람이라는 건 아주 잘 전해졌거든요.","JPN":"短い付き合いでしたが、あなたが素直じゃないってのはとてもよく伝わってきたんで。","ENG":"Although we've only known each other for a short time, I knew that you were never one to be fully honest with others.","TWN":"我和你認識的時間不長，但能感受到你是一個非常不真實的人。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"그러니까 저는….","JPN":"だから、私は……","ENG":"That's why I...","TWN":"所以我……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"때려 눕혀서라도 당신의 진심을 확인해야겠어요.","JPN":"打ちのめしてでも、あなたの本心を確認するつもりです。","ENG":"will go as far as to knock you down just to hear what you truly think.","TWN":"決定把你打趴下，再親自確認你的真心。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};